                  </div>
                )}

                {/* Ricavo */}
                {uscita.prezzo_kg && uscita.peso_carcassa && (
                  <div style={{ background:C.green+"12", borderRadius:12, padding:"12px 16px", border:`1.5px solid ${C.green}33` }}>
